insert into public.categories (id, name, slug, description, sort_order, image_url, is_active) values
  ('c1000000-0000-0000-0000-000000000001', 'Smartphones', 'smartphones', 'Apple iPhone and Samsung Galaxy smartphones.', 1, 'https://joetheproz5.github.io/joe-s-shop/catalog/apple/iphone-17.png', true),
  ('c1000000-0000-0000-0000-000000000002', 'Laptops', 'laptops', 'MacBook Air and MacBook Pro powered by Apple M5 chips.', 2, 'https://joetheproz5.github.io/joe-s-shop/catalog/apple/macbook-air-m5.png', true),
  ('c1000000-0000-0000-0000-000000000003', 'Audio', 'audio', 'Wireless earbuds and over-ear headphones.', 3, 'https://joetheproz5.github.io/joe-s-shop/catalog/apple/airpods-pro-3.png', true),
  ('c1000000-0000-0000-0000-000000000004', 'Smartwatches', 'smartwatches', 'Apple Watch and Samsung Galaxy Watch models.', 4, 'https://joetheproz5.github.io/joe-s-shop/catalog/apple/watch-series-11.png', true),
  ('c1000000-0000-0000-0000-000000000005', 'Charging & Cables', 'charging-cables', 'Official charging cables and wireless chargers.', 5, 'https://joetheproz5.github.io/joe-s-shop/catalog/apple/magsafe-charger.jpg', true);
insert into public.products (id, name, slug, short_description, description, sku, brand_id, cost_price, selling_price, stock_quantity, low_stock_threshold, status, is_featured, is_new_arrival, is_best_seller, seo_title, seo_description) values
  ('a1000000-0000-0000-0000-000000000001', 'iPhone 17', 'iphone-17', '6.3-inch ProMotion display, A19 chip, and 48MP Dual Fusion camera system.', 'iPhone 17 features a 6.3-inch Super Retina XDR display with ProMotion up to 120Hz, the A19 chip, an 18MP Center Stage front camera, and a 48MP Dual Fusion camera system.', 'APL-IP17-256', 'b1000000-0000-0000-0000-000000000001', 0, 799, 36, 5, 'active', true, true, true, 'iPhone 17 | Joe''s Shop', '6.3-inch ProMotion display, A19 chip, and 48MP Dual Fusion camera system.'),
  ('a1000000-0000-0000-0000-000000000002', 'iPhone Air', 'iphone-air', 'Apple''s thinnest iPhone with a 6.5-inch display and A19 Pro chip.', 'iPhone Air combines an exceptionally thin titanium design with a 6.5-inch Super Retina XDR display, ProMotion up to 120Hz, the A19 Pro chip, and a 48MP Fusion camera.', 'APL-IPAIR-256', 'b1000000-0000-0000-0000-000000000001', 0, 999, 24, 5, 'active', true, true, false, 'iPhone Air | Joe''s Shop', 'Apple''s thinnest iPhone with a 6.5-inch display and A19 Pro chip.'),
  ('a1000000-0000-0000-0000-000000000003', 'iPhone 17 Pro', 'iphone-17-pro', '6.3-inch pro iPhone with A19 Pro and three 48MP Fusion cameras.', 'iPhone 17 Pro pairs the A19 Pro chip with a 6.3-inch Super Retina XDR display, a vapor-cooled aluminum unibody, and three 48MP Fusion cameras with up to 8x optical-quality zoom.', 'APL-IP17P-256', 'b1000000-0000-0000-0000-000000000001', 0, 1099, 28, 5, 'active', true, true, true, 'iPhone 17 Pro | Joe''s Shop', '6.3-inch pro iPhone with A19 Pro and three 48MP Fusion cameras.'),
  ('a1000000-0000-0000-0000-000000000004', 'iPhone 17 Pro Max', 'iphone-17-pro-max', '6.9-inch flagship iPhone with A19 Pro and the longest iPhone battery life.', 'iPhone 17 Pro Max brings the A19 Pro chip, a 6.9-inch Super Retina XDR display, three 48MP Fusion cameras, and up to 8x optical-quality zoom to Apple''s largest pro iPhone.', 'APL-IP17PM-256', 'b1000000-0000-0000-0000-000000000001', 0, 1199, 22, 5, 'active', true, true, false, 'iPhone 17 Pro Max | Joe''s Shop', '6.9-inch flagship iPhone with A19 Pro and the longest iPhone battery life.'),
  ('a1000000-0000-0000-0000-000000000005', 'MacBook Air 13-inch M5', 'macbook-air-13-m5', 'Portable 13-inch MacBook Air with M5, 512GB storage, and up to 18 hours of battery life.', 'The 13-inch MacBook Air with M5 starts with 512GB of storage and adds Wi-Fi 7, Bluetooth 6, a Liquid Retina display, and up to 18 hours of battery life in a lightweight fanless design.', 'APL-MBA13-M5', 'b1000000-0000-0000-0000-000000000001', 0, 1099, 18, 5, 'active', true, true, true, 'MacBook Air 13-inch M5 | Joe''s Shop', 'Portable 13-inch MacBook Air with M5, 512GB storage, and up to 18 hours of battery life.'),
  ('a1000000-0000-0000-0000-000000000006', 'MacBook Air 15-inch M5', 'macbook-air-15-m5', 'Roomy 15-inch MacBook Air with M5 and up to 18 hours of battery life.', 'The 15-inch MacBook Air with M5 offers a larger Liquid Retina display, standard 512GB storage, Wi-Fi 7, Bluetooth 6, and up to 18 hours of battery life in a thin fanless enclosure.', 'APL-MBA15-M5', 'b1000000-0000-0000-0000-000000000001', 0, 1299, 14, 5, 'active', false, true, false, 'MacBook Air 15-inch M5 | Joe''s Shop', 'Roomy 15-inch MacBook Air with M5 and up to 18 hours of battery life.'),
  ('a1000000-0000-0000-0000-000000000007', 'MacBook Pro 14-inch M5', 'macbook-pro-14-m5', '14-inch Liquid Retina XDR notebook with M5 and 1TB starting storage.', 'The 14-inch MacBook Pro with M5 combines a Liquid Retina XDR display, 12MP Center Stage camera, six-speaker sound, up to 24 hours of battery life, and 1TB of starting storage.', 'APL-MBP14-M5', 'b1000000-0000-0000-0000-000000000001', 0, 1699, 16, 5, 'active', true, true, false, 'MacBook Pro 14-inch M5 | Joe''s Shop', '14-inch Liquid Retina XDR notebook with M5 and 1TB starting storage.'),
  ('a1000000-0000-0000-0000-000000000008', 'MacBook Pro 14-inch M5 Pro', 'macbook-pro-14-m5-pro', 'Compact pro notebook with M5 Pro, Thunderbolt 5, and 1TB starting storage.', 'The 14-inch MacBook Pro with M5 Pro delivers high-performance CPU and GPU cores, Thunderbolt 5, Wi-Fi 7, Bluetooth 6, a Liquid Retina XDR display, and up to 24 hours of battery life.', 'APL-MBP14-M5P', 'b1000000-0000-0000-0000-000000000001', 0, 2199, 12, 5, 'active', false, true, false, 'MacBook Pro 14-inch M5 Pro | Joe''s Shop', 'Compact pro notebook with M5 Pro, Thunderbolt 5, and 1TB starting storage.'),
  ('a1000000-0000-0000-0000-000000000009', 'MacBook Pro 16-inch M5 Pro', 'macbook-pro-16-m5-pro', '16-inch professional notebook with M5 Pro and 1TB starting storage.', 'The 16-inch MacBook Pro with M5 Pro offers a large Liquid Retina XDR display, Thunderbolt 5, Wi-Fi 7, Bluetooth 6, 1TB starting storage, and up to 24 hours of battery life.', 'APL-MBP16-M5P', 'b1000000-0000-0000-0000-000000000001', 0, 2699, 10, 5, 'active', false, true, false, 'MacBook Pro 16-inch M5 Pro | Joe''s Shop', '16-inch professional notebook with M5 Pro and 1TB starting storage.'),
  ('a1000000-0000-0000-0000-000000000010', 'MacBook Pro 16-inch M5 Max', 'macbook-pro-16-m5-max', 'Apple''s highest-performance 16-inch notebook with M5 Max and 2TB starting storage.', 'The 16-inch MacBook Pro with M5 Max is built for demanding professional workflows with high-bandwidth unified memory, Thunderbolt 5, Wi-Fi 7, Bluetooth 6, and 2TB of starting storage.', 'APL-MBP16-M5X', 'b1000000-0000-0000-0000-000000000001', 0, 3899, 7, 5, 'active', false, true, false, 'MacBook Pro 16-inch M5 Max | Joe''s Shop', 'Apple''s highest-performance 16-inch notebook with M5 Max and 2TB starting storage.'),
  ('a1000000-0000-0000-0000-000000000011', 'AirPods 4', 'airpods-4', 'Open-fit wireless earbuds with the H2 chip and Personalized Spatial Audio.', 'AirPods 4 feature a redesigned open fit, the H2 chip, Voice Isolation, Personalized Spatial Audio, USB-C charging, and an IP54 dust, sweat, and water resistance rating.', 'APL-AP4', 'b1000000-0000-0000-0000-000000000001', 0, 129, 48, 5, 'active', false, false, true, 'AirPods 4 | Joe''s Shop', 'Open-fit wireless earbuds with the H2 chip and Personalized Spatial Audio.'),
  ('a1000000-0000-0000-0000-000000000012', 'AirPods 4 with Active Noise Cancellation', 'airpods-4-active-noise-cancellation', 'AirPods 4 with Active Noise Cancellation, Adaptive Audio, and wireless charging.', 'This AirPods 4 model adds Active Noise Cancellation, Transparency mode, Adaptive Audio, Conversation Awareness, and a wireless charging case with a built-in speaker.', 'APL-AP4-ANC', 'b1000000-0000-0000-0000-000000000001', 0, 179, 38, 5, 'active', false, false, false, 'AirPods 4 with Active Noise Cancellation | Joe''s Shop', 'AirPods 4 with Active Noise Cancellation, Adaptive Audio, and wireless charging.'),
  ('a1000000-0000-0000-0000-000000000013', 'AirPods Pro 3', 'airpods-pro-3', 'In-ear AirPods with advanced ANC, heart-rate sensing, and improved fit.', 'AirPods Pro 3 deliver stronger in-ear Active Noise Cancellation, a redesigned fit with five ear-tip sizes, heart-rate sensing during workouts, and extended battery life.', 'APL-APP3', 'b1000000-0000-0000-0000-000000000001', 0, 249, 34, 5, 'active', true, true, true, 'AirPods Pro 3 | Joe''s Shop', 'In-ear AirPods with advanced ANC, heart-rate sensing, and improved fit.'),
  ('a1000000-0000-0000-0000-000000000014', 'AirPods Max 2', 'airpods-max-2', 'Premium over-ear headphones with high-fidelity audio and Active Noise Cancellation.', 'AirPods Max 2 combine a comfortable over-ear design with high-fidelity audio, Active Noise Cancellation, Transparency mode, Personalized Spatial Audio, and USB-C charging.', 'APL-APMAX2', 'b1000000-0000-0000-0000-000000000001', 0, 549, 15, 5, 'active', false, true, false, 'AirPods Max 2 | Joe''s Shop', 'Premium over-ear headphones with high-fidelity audio and Active Noise Cancellation.'),
  ('a1000000-0000-0000-0000-000000000015', 'Apple Watch Series 11', 'apple-watch-series-11', 'Thin everyday smartwatch with health insights and up to 24 hours of battery life.', 'Apple Watch Series 11 offers an always-on display, comprehensive fitness and health features, 5G cellular options, sleep score, and up to 24 hours of battery life.', 'APL-AWS11', 'b1000000-0000-0000-0000-000000000001', 0, 399, 26, 5, 'active', true, true, false, 'Apple Watch Series 11 | Joe''s Shop', 'Thin everyday smartwatch with health insights and up to 24 hours of battery life.'),
  ('a1000000-0000-0000-0000-000000000016', 'Apple Watch SE 3', 'apple-watch-se-3', 'Essential Apple Watch features at the most accessible price.', 'Apple Watch SE 3 brings core activity, workout, safety, communication, and health features in a lightweight aluminum design with GPS and cellular options.', 'APL-AWSE3', 'b1000000-0000-0000-0000-000000000001', 0, 249, 30, 5, 'active', false, true, false, 'Apple Watch SE 3 | Joe''s Shop', 'Essential Apple Watch features at the most accessible price.'),
  ('a1000000-0000-0000-0000-000000000017', 'Apple Watch Ultra 3', 'apple-watch-ultra-3', 'Rugged titanium Apple Watch for endurance, adventure, and water sports.', 'Apple Watch Ultra 3 is Apple''s most rugged smartwatch, with a titanium case, precision dual-frequency GPS, advanced training features, cellular connectivity, and extended battery life.', 'APL-AWU3', 'b1000000-0000-0000-0000-000000000001', 0, 799, 12, 5, 'active', false, true, false, 'Apple Watch Ultra 3 | Joe''s Shop', 'Rugged titanium Apple Watch for endurance, adventure, and water sports.'),
  ('a1000000-0000-0000-0000-000000000018', 'Apple MagSafe Charger (1m)', 'apple-magsafe-charger-1m', 'Qi2-certified magnetic wireless charger with an integrated 1-meter USB-C cable.', 'The Apple MagSafe Charger provides magnetic alignment and wireless charging up to 25W with a compatible power adapter. It also supports Qi2 and Qi charging.', 'APL-MGD74', 'b1000000-0000-0000-0000-000000000001', 0, 39, 42, 5, 'active', false, false, true, 'Apple MagSafe Charger (1m) | Joe''s Shop', 'Qi2-certified magnetic wireless charger with an integrated 1-meter USB-C cable.'),
  ('a1000000-0000-0000-0000-000000000019', 'Apple 60W USB-C Charge Cable (1m)', 'apple-60w-usb-c-charge-cable-1m', 'Woven USB-C charge and sync cable supporting up to 60 watts.', 'This woven 1-meter USB-C to USB-C cable supports charging up to 60W, USB 2 data transfer, syncing, and fast charging with a compatible USB-C power adapter.', 'APL-MW493', 'b1000000-0000-0000-0000-000000000001', 0, 19, 64, 5, 'active', false, false, false, 'Apple 60W USB-C Charge Cable (1m) | Joe''s Shop', 'Woven USB-C charge and sync cable supporting up to 60 watts.'),
  ('a2000000-0000-0000-0000-000000000001', 'Samsung Galaxy S23', 'samsung-galaxy-s23', 'Compact 6.1-inch Galaxy flagship with a 50MP camera and Snapdragon 8 Gen 2 for Galaxy.', 'Galaxy S23 features a 6.1-inch Dynamic AMOLED 2X display, Snapdragon 8 Gen 2 Mobile Platform for Galaxy, a 50MP main camera, and a durable IP68-rated design.', 'SAM-S23-128', 'b1000000-0000-0000-0000-000000000002', 0, 799.99, 30, 5, 'active', false, false, true, 'Samsung Galaxy S23 | Joe''s Shop', 'Compact 6.1-inch Galaxy flagship with a 50MP camera and Snapdragon 8 Gen 2 for Galaxy.'),
  ('a2000000-0000-0000-0000-000000000002', 'Samsung Galaxy S23+', 'samsung-galaxy-s23-plus', '6.6-inch Galaxy flagship with a 50MP camera and 256GB starting storage.', 'Galaxy S23+ pairs a 6.6-inch Dynamic AMOLED 2X display with Snapdragon 8 Gen 2 for Galaxy, a 50MP main camera, 45W wired charging, and 256GB starting storage.', 'SAM-S23P-256', 'b1000000-0000-0000-0000-000000000002', 0, 999.99, 22, 5, 'active', false, false, false, 'Samsung Galaxy S23+ | Joe''s Shop', '6.6-inch Galaxy flagship with a 50MP camera and 256GB starting storage.'),
  ('a2000000-0000-0000-0000-000000000003', 'Samsung Galaxy S23 Ultra', 'samsung-galaxy-s23-ultra', '6.8-inch Galaxy flagship with an integrated S Pen and 200MP camera.', 'Galaxy S23 Ultra combines a 6.8-inch Dynamic AMOLED 2X display, integrated S Pen, 200MP camera, Snapdragon 8 Gen 2 for Galaxy, and a 5,000mAh battery.', 'SAM-S23U-256', 'b1000000-0000-0000-0000-000000000002', 0, 1199.99, 20, 5, 'active', true, false, true, 'Samsung Galaxy S23 Ultra | Joe''s Shop', '6.8-inch Galaxy flagship with an integrated S Pen and 200MP camera.'),
  ('a2000000-0000-0000-0000-000000000004', 'Samsung Galaxy S23 FE', 'samsung-galaxy-s23-fe', '6.4-inch Galaxy phone with a 50MP camera and flagship-inspired features.', 'Galaxy S23 FE offers a 6.4-inch Dynamic AMOLED 2X display, a 50MP high-resolution camera with 3x optical zoom, a 4,500mAh battery, and IP68 water and dust resistance.', 'SAM-S23FE-128', 'b1000000-0000-0000-0000-000000000002', 0, 599, 32, 5, 'active', false, false, false, 'Samsung Galaxy S23 FE | Joe''s Shop', '6.4-inch Galaxy phone with a 50MP camera and flagship-inspired features.'),
  ('a2000000-0000-0000-0000-000000000005', 'Samsung Galaxy Buds4', 'samsung-galaxy-buds4', 'Open-fit earbuds with 24-bit Hi-Fi audio, ANC, and intelligent controls.', 'Galaxy Buds4 use an open-fit design with an 11mm dynamic speaker, 24-bit Hi-Fi audio support, Active Noise Cancellation, voice controls, and a compact transparent charging case.', 'SAM-BUDS4', 'b1000000-0000-0000-0000-000000000002', 0, 179.99, 40, 5, 'active', false, true, false, 'Samsung Galaxy Buds4 | Joe''s Shop', 'Open-fit earbuds with 24-bit Hi-Fi audio, ANC, and intelligent controls.'),
  ('a2000000-0000-0000-0000-000000000006', 'Samsung Galaxy Buds4 Pro', 'samsung-galaxy-buds4-pro', 'Canal-fit premium earbuds with enhanced two-way speakers and adaptive ANC.', 'Galaxy Buds4 Pro feature an enhanced two-way speaker system, 24-bit Hi-Fi audio support, adaptive Active Noise Cancellation, a secure canal fit, and intelligent hands-free controls.', 'SAM-BUDS4P', 'b1000000-0000-0000-0000-000000000002', 0, 249.99, 34, 5, 'active', true, true, true, 'Samsung Galaxy Buds4 Pro | Joe''s Shop', 'Canal-fit premium earbuds with enhanced two-way speakers and adaptive ANC.'),
  ('a2000000-0000-0000-0000-000000000007', 'Samsung Galaxy Watch8', 'samsung-galaxy-watch8', 'Thin everyday Galaxy watch with personalized wellness and running insights.', 'Galaxy Watch8 features Samsung''s cushion design, a Super AMOLED display, dual-frequency GPS, advanced health tracking, Wear OS 6, and One UI 8 Watch.', 'SAM-WATCH8-40', 'b1000000-0000-0000-0000-000000000002', 0, 349.99, 24, 5, 'active', true, true, false, 'Samsung Galaxy Watch8 | Joe''s Shop', 'Thin everyday Galaxy watch with personalized wellness and running insights.'),
  ('a2000000-0000-0000-0000-000000000008', 'Samsung Galaxy Watch8 Classic', 'samsung-galaxy-watch8-classic', '46mm Galaxy smartwatch with a rotating bezel and Quick Button.', 'Galaxy Watch8 Classic combines a 46mm cushion-shaped case with a rotating bezel, Quick Button, Super AMOLED display, 64GB of storage, and personalized health insights.', 'SAM-WATCH8C-46', 'b1000000-0000-0000-0000-000000000002', 0, 499.99, 18, 5, 'active', false, true, false, 'Samsung Galaxy Watch8 Classic | Joe''s Shop', '46mm Galaxy smartwatch with a rotating bezel and Quick Button.'),
  ('a2000000-0000-0000-0000-000000000009', 'Samsung Galaxy Watch Ultra', 'samsung-galaxy-watch-ultra', 'Durable titanium Galaxy watch with dual-frequency GPS and extended battery life.', 'Galaxy Watch Ultra is Samsung''s most durable smartwatch, with a titanium cushion design, dual-frequency GPS, 10ATM water resistance, 64GB storage, and advanced fitness tracking.', 'SAM-WATCHU', 'b1000000-0000-0000-0000-000000000002', 0, 649.99, 13, 5, 'active', false, true, false, 'Samsung Galaxy Watch Ultra | Joe''s Shop', 'Durable titanium Galaxy watch with dual-frequency GPS and extended battery life.'),
  ('a2000000-0000-0000-0000-000000000010', 'Samsung USB-C to USB-C Cable', 'samsung-usb-c-to-usb-c-cable', 'Official 1.8-meter 3A USB-C cable for charging and data transfer.', 'Samsung''s 1.8-meter USB-C to USB-C cable supports up to 3A charging and reliable data transfer for compatible Galaxy phones, tablets, earbuds, and other USB-C devices.', 'SAM-EP-DX310', 'b1000000-0000-0000-0000-000000000002', 0, 14.99, 70, 5, 'active', false, false, false, 'Samsung USB-C to USB-C Cable | Joe''s Shop', 'Official 1.8-meter 3A USB-C cable for charging and data transfer.'),
  ('a2000000-0000-0000-0000-000000000011', 'Samsung Galaxy Watch Fast Charger', 'samsung-galaxy-watch-fast-charger', 'Official USB-C magnetic fast charger for Galaxy Watch5 and later.', 'The Samsung Galaxy Watch Fast Charger uses a compact magnetic charging puck and USB-C connection for fast charging on Galaxy Watch5 series and later models.', 'SAM-EP-OL300', 'b1000000-0000-0000-0000-000000000002', 0, 39.99, 38, 5, 'active', false, false, false, 'Samsung Galaxy Watch Fast Charger | Joe''s Shop', 'Official USB-C magnetic fast charger for Galaxy Watch5 and later.'),
  ('a2000000-0000-0000-0000-000000000012', 'Samsung Galaxy S26', 'samsung-galaxy-s26', 'Compact 6.3-inch Galaxy flagship with a 50MP camera and Galaxy AI.', 'Galaxy S26 combines a 6.3-inch Dynamic AMOLED 2X display, a 50MP wide camera, Snapdragon 8 Elite Gen 5 for Galaxy, a 4,300mAh battery, and deeply integrated Galaxy AI features.', 'SAM-S26-256', 'b1000000-0000-0000-0000-000000000002', 0, 899.99, 32, 5, 'active', true, true, true, 'Samsung Galaxy S26 | Joe''s Shop', 'Compact 6.3-inch Galaxy flagship with a 50MP camera and Galaxy AI.'),
  ('a2000000-0000-0000-0000-000000000013', 'Samsung Galaxy S26+', 'samsung-galaxy-s26-plus', 'Large 6.7-inch Galaxy flagship with a 50MP camera and 4,900mAh battery.', 'Galaxy S26+ pairs a 6.7-inch Dynamic AMOLED 2X display with a 50MP wide camera, Snapdragon 8 Elite Gen 5 for Galaxy, a 4,900mAh battery, and advanced Galaxy AI tools.', 'SAM-S26P-256', 'b1000000-0000-0000-0000-000000000002', 0, 1099.99, 24, 5, 'active', false, true, false, 'Samsung Galaxy S26+ | Joe''s Shop', 'Large 6.7-inch Galaxy flagship with a 50MP camera and 4,900mAh battery.'),
  ('a2000000-0000-0000-0000-000000000014', 'Samsung Galaxy S26 Ultra', 'samsung-galaxy-s26-ultra', '6.9-inch Galaxy Ultra with a 200MP camera, S Pen, and built-in Privacy Display.', 'Galaxy S26 Ultra features a 6.9-inch display with built-in Privacy Display, a 200MP wide camera, integrated S Pen, Snapdragon 8 Elite Gen 5 for Galaxy, and a 5,000mAh battery.', 'SAM-S26U-256', 'b1000000-0000-0000-0000-000000000002', 0, 1299.99, 20, 5, 'active', true, true, true, 'Samsung Galaxy S26 Ultra | Joe''s Shop', '6.9-inch Galaxy Ultra with a 200MP camera, S Pen, and built-in Privacy Display.'),
  ('a2000000-0000-0000-0000-000000000015', 'Samsung Galaxy Z Fold7', 'samsung-galaxy-z-fold7', 'Slim foldable with an expansive 8-inch main display and 200MP camera.', 'Galaxy Z Fold7 opens to an expansive 8-inch main display and combines a wider cover screen, 200MP wide camera, Snapdragon 8 Elite for Galaxy, 4,400mAh battery, and foldable-optimized Galaxy AI.', 'SAM-ZFOLD7-256', 'b1000000-0000-0000-0000-000000000002', 0, 1999.99, 12, 5, 'active', true, true, false, 'Samsung Galaxy Z Fold7 | Joe''s Shop', 'Slim foldable with an expansive 8-inch main display and 200MP camera.'),
  ('a2000000-0000-0000-0000-000000000016', 'Samsung Galaxy Z Flip7', 'samsung-galaxy-z-flip7', 'Pocketable Galaxy foldable with a flexible main display and 50MP camera.', 'Galaxy Z Flip7 folds into a compact pocketable design while offering a large edge-to-edge cover screen, a flexible main display, 50MP wide camera, and Galaxy AI experiences designed for the Flip form factor.', 'SAM-ZFLIP7-256', 'b1000000-0000-0000-0000-000000000002', 0, 1099.99, 18, 5, 'active', false, true, false, 'Samsung Galaxy Z Flip7 | Joe''s Shop', 'Pocketable Galaxy foldable with a flexible main display and 50MP camera.');
